import { createContext, useContext, useMemo, useState, useEffect } from "react";
import { jwtDecode } from "jwt-decode";
import api from "./api";

const AuthContext = createContext(null);

// Chuẩn hoá roles từ token
function normalizeRoles(payload) {
    let raw =
        payload.roles ??
        payload.authorities ??
        payload.role ??
        payload.scope ??
        [];
    if (typeof raw === "string") raw = raw.split(/\s+/).filter(Boolean);
    if (!Array.isArray(raw)) raw = [raw];

    return raw
        .map(r => (typeof r === "string" ? r : String(r)))
        .map(r => (r.startsWith("ROLE_") ? r.slice(5) : r));
}

export function AuthProvider({ children }) {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const t = localStorage.getItem("access_token");
        if (t) {
            try {
                const p = jwtDecode(t);
                setUser({
                    username: p.sub || p.username,
                    roles: normalizeRoles(p),
                });
            } catch {
                localStorage.removeItem("access_token");
            }
        }
        setLoading(false);
    }, []);

    const login = async (username, password) => {
        const { data } = await api.post("/api/auth/login", { username, password });
        const token = data.token || data.accessToken;
        localStorage.setItem("access_token", token);
        const p = jwtDecode(token);
        setUser({
            username: p.sub || p.username,
            roles: normalizeRoles(p),
        });
    };

    const logout = () => {
        localStorage.removeItem("access_token");
        setUser(null);
    };

    const value = useMemo(() => ({ user, loading, login, logout }), [user, loading]);
    return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export const useAuth = () => useContext(AuthContext);

export const hasRole = (user, ...roles) => {
    if (!user?.roles) return false;
    return roles.some(r => user.roles.includes(r));
};
